    /// <summary>
    /// Cause when `status === ChangesetStatus.Error`; otherwise omitted.
    /// </summary>
    [JsonPropertyName("error")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ErrorInfo? Error { get; set; }
}

