}

// ─── StateAction Union ───────────────────────────────────────────────

/// <summary>
/// StateAction is the discriminated union of every state action.
/// </summary>
[JsonConverter(typeof(StateActionConverter))]
public sealed class StateAction : AhpUnion
{
    /// <summary>Creates an empty StateAction (no active variant).</summary>
    public StateAction() { }

    /// <summary>Creates a StateAction wrapping the given variant value.</summary>
    public StateAction(object? value) : base(value) { }
